const API_BASE = 'https://api.ivxholding.com';

function redact(token) {
  if (!token || token.length < 8) return 'empty';
  return `${token.slice(0, 4)}****${token.slice(-4)}`;
}

async function testGitHubToken() {
  const response = await fetch('https://api.github.com/user', {
    headers: { Authorization: `token ${GITHUB_TOKEN}` },
  });
  const text = await response.text();
  return { ok: response.ok, status: response.status, preview: text.slice(0, 120) };
}

async function testRenderKey() {
  const response = await fetch('https://api.render.com/v1/services?limit=20', {
    headers: { Authorization: `Bearer ${RENDER_API_KEY}`, Accept: 'application/json' },
  });
  const text = await response.text();
  let services = [];
  try {
    services = JSON.parse(text);
  } catch {}
  const match = services.find((s) => s.service?.name === RENDER_SERVICE_NAME || s.name === RENDER_SERVICE_NAME);
  return { ok: response.ok, status: response.status, serviceId: match?.service?.id || match?.id || null, servicesCount: services.length, preview: text.slice(0, 200) };
}

async function testSupabaseServiceRole() {
  const endpoint = `${SUPABASE_URL.replace(/\/+$/, '')}/auth/v1/admin/users?page=1&per_page=1`;
  const response = await fetch(endpoint, {
    headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}` },
  });
  const text = await response.text();
  return { ok: response.ok, status: response.status, preview: text.slice(0, 120) };
}

async function testLiveOwnerLogin() {
  const response = await fetch(`${API_BASE}/api/ivx/owner-passwordless-login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email: IVX_OWNER_EMAIL }),
  });
  const text = await response.text();
  return { status: response.status, preview: text.slice(0, 200) };
}

async function testLiveOwnerVariables() {
  const response = await fetch(`${API_BASE}/api/ivx/owner-variables/status`, {
    headers: { Authorization: `Bearer ${IVX_OWNER_TOKEN}` },
  });
  const text = await response.text();
  return { status: response.status, preview: text.slice(0, 200) };
}

async function testLiveHealth() {
  const response = await fetch(`${API_BASE}/health`);
  const text = await response.text();
  return { status: response.status, body: text };
}

const results = {
  timestamp: new Date().toISOString(),
  githubToken: redact(GITHUB_TOKEN),
  renderKey: redact(RENDER_API_KEY),
  supabaseServiceRoleKey: redact(SUPABASE_SERVICE_ROLE_KEY),
  ownerEmail: IVX_OWNER_EMAIL,
  ownerPassword: redact(IVX_OWNER_PASSWORD),
  ownerToken: redact(IVX_OWNER_TOKEN),
  githubTest: await testGitHubToken(),
  renderTest: await testRenderKey(),
  supabaseTest: await testSupabaseServiceRole(),
  liveOwnerLogin: await testLiveOwnerLogin(),
  liveOwnerVariables: await testLiveOwnerVariables(),
  liveHealth: await testLiveHealth(),
};

console.log(JSON.stringify(results, null, 2));
