// 3. POST no email
results.push({ step: 'POST /api/ivx/owner-passwordless-login (no email)', ...await request('POST', '/api/ivx/owner-passwordless-login', {}, { 'Content-Type': 'application/json' }) });

// 4. POST non-allowlist
results.push({ step: 'POST /api/ivx/owner-passwordless-login (non-allowlist)', ...await request('POST', '/api/ivx/owner-passwordless-login', { email: NON_OWNER_EMAIL }, { 'Content-Type': 'application/json' }) });

// 5. POST real owner
const loginResult = await request('POST', '/api/ivx/owner-passwordless-login', { email: OWNER_EMAIL }, { 'Content-Type': 'application/json' });
results.push({ step: 'POST /api/ivx/owner-passwordless-login (real owner)', status: loginResult.status, text: loginResult.text.slice(0, 200) });

let accessToken = '';
try {
  const parsed = JSON.parse(loginResult.text);
  accessToken = parsed.accessToken || '';
} catch {}

// 6. owner-variables/status no auth
results.push({ step: 'GET /api/ivx/owner-variables/status (no auth)', ...await request('GET', '/api/ivx/owner-variables/status') });

// 7. owner-variables/status with owner token
results.push({ step: 'GET /api/ivx/owner-variables/status (owner token)', ...await request('GET', '/api/ivx/owner-variables/status', null, { Authorization: `Bearer ${OWNER_TOKEN}` }) });

// 8. owner-variables/status with Supabase access token from login
if (accessToken) {
  results.push({ step: 'GET /api/ivx/owner-variables/status (Supabase bearer)', ...await request('GET', '/api/ivx/owner-variables/status', null, { Authorization: `Bearer ${accessToken}` }) });
}

// 9. version
results.push({ step: 'GET /version', ...await request('GET', '/version') });

const summary = results.map((r) => ({
  step: r.step,
  status: r.status,
  ok: r.status >= 200 && r.status < 300,
  preview: (r.text || r.body || '').toString().slice(0, 120),
}));

